code = """import json
import os

# Load CLRB data and calculate volatile days
clrb_file = locals()['var_functions.query_db:50']
with open(clrb_file, 'r') as f:
    clrb_data = json.load(f)

clrb_volatile = 0
for day in clrb_data:
    high = float(day['High'])
    low = float(day['Low'])
    if low > 0 and (high - low) / low > 0.20:
        clrb_volatile += 1

# Load IDEX data and calculate volatile days
idex_file = locals()['var_functions.query_db:54']
with open(idex_file, 'r') as f:
    idex_data = json.load(f)

idex_volatile = 0
for day in idex_data:
    high = float(day['High'])
    low = float(day['Low'])
    if low > 0 and (high - low) / low > 0.20:
        idex_volatile += 1

print('__RESULT__:')
print(json.dumps({
    'BIOC': {'symbol': 'BIOC', 'company': 'Biocept Inc.', 'volatile_days': 21},
    'CLRB': {'symbol': 'CLRB', 'company': 'Cellectar Biosciences Inc.', 'volatile_days': clrb_volatile},
    'IDEX': {'symbol': 'IDEX', 'company': 'Ideanomics Inc.', 'volatile_days': idex_volatile}
}))"""

